# Let's write a small C# program to parse the binlog
mkdir -p /tmp/binlog-reader && cd /tmp/binlog-reader && cat > binlog-reader.csproj << 'EOF'
<Project Sdk="Microsoft.NET.Sdk">
  <PropertyGroup>
    <OutputType>Exe</OutputType>
    <TargetFramework>net9.0</TargetFramework>
  </PropertyGroup>
  <ItemGroup>
    <PackageReference Include="MSBuild.StructuredLogger" Version="2.2.385" />
  </ItemGroup>
</Project>
EOF
cat > Program.cs << 'EOF'
using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;
using System.Collections.Generic;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine("=== BUILD RESULT: " + (build.Succeeded ? "SUCCESS" : "FAILED") + " ===\n");

// Collect all errors
var errors = new List<(string project, string code, string message, string file, int line)>();

build.VisitAllChildren<Error>(error => {
    var project = "";
    var node = error.Parent;
    while (node != null) {
        if (node is Project p) { project = p.Name; break; }
        node = node.Parent;
    }
    errors.Add((project, error.Code ?? "", error.Text ?? error.ToString(), error.File ?? "", error.LineNumber));
});

Console.WriteLine($"Total errors: {errors.Count}\n");

// Group by project
var byProject = errors.GroupBy(e => e.project).OrderBy(g => g.Key);
foreach (var group in byProject) {
    Console.WriteLine($"--- Project: {group.Key} ---");
    foreach (var e in group) {
        Console.WriteLine($"  [{e.code}] {e.file}({e.line}): {e.message}");
    }
    Console.WriteLine();
}

// Also look for failed targets/projects
Console.WriteLine("=== FAILED PROJECTS ===");
build.VisitAllChildren<Project>(p => {
    if (!p.Succeeded) {
        Console.WriteLine($"  FAILED: {p.Name} (target: {p.TargetFramework})");
    }
});
EOF
