using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Show warnings too, especially NU* warnings
Console.WriteLine("=== NUGET / PACKAGE WARNINGS ===");
build.VisitAllChildren<Warning>(w => {
    if (w.Code != null && (w.Code.StartsWith("NU") || w.Code.StartsWith("CS"))) {
        var project = "";
        var node = w.Parent;
        while (node != null) {
            if (node is Project p) { project = p.Name; break; }
            node = node.Parent;
        }
        Console.WriteLine($"  [{w.Code}] {project}: {w.Text}");
    }
});

// Show project references and package references for Services.csproj
Console.WriteLine("\n=== ITEMS FOR Services.csproj ===");
build.VisitAllChildren<Project>(p => {
    if (p.Name == "Services.csproj") {
        Console.WriteLine($"Project: {p.Name}, ProjectFile: {p.ProjectFile}");
        p.VisitAllChildren<AddItem>(item => {
            if (item.Name == "PackageReference" || item.Name == "ProjectReference" || item.Name == "Reference") {
                Console.WriteLine($"  {item.Name}: {item.Title}");
                foreach (var child in item.Children) {
                    Console.WriteLine($"    -> {child}");
                }
            }
        });
    }
});

// Also show all projects in the build
Console.WriteLine("\n=== ALL PROJECTS ===");
build.VisitAllChildren<Project>(p => {
    Console.WriteLine($"  {p.Name} ({p.ProjectFile})");
});
EOF
